var ContactForm = {

  init: function() {
    $('.contact-form')
      .on('ajax:success', function(e) {
        e.preventDefault();
        let wrapper = $(e.target).parents('.contact-form-widget');
        $(this).removeClass('was-validated');
        $(this)[0].reset();
        wrapper.find('.success-message').show();
      })
      .on('ajax:error', function(e) {
        e.preventDefault();
        let wrapper = $(e.target).parents('.contact-form-widget');
        wrapper.find('.error-message').show();
      })
      .validate({
        rules: {
          'name': {
            minlength: 2,
            required: true
          },
          'contact': {
            minlength: 2,
            required: true,
          }
        },
        highlight: function (element) {
          $(element).closest('.control-group').removeClass('success').addClass('error');
        },
        success: function (element) {
          element
            .addClass('valid')
            .closest('.control-group').removeClass('error').addClass('success');
        }
      });
  }

};
;
var CookieManager = {

  init: function() {
    CookieManager.check_cookie_approval();
    $('#cookie-approve-btn').on('click', function() {
      CookieManager.cookie_approval();
    });
  },

  // Gets cookie by name.
  get_cookie: function(name) {
    var value = "; " + document.cookie;
    var parts = value.split("; " + name + "=");
    if (parts.length == 2) return parts.pop().split(";").shift();
  },

  // Sets cookie with given params.
  set_cookie: function(key, value, exp, path) {
    document.cookie= key + "=" + value + "; expires=" + exp + "; path=" + path;
  },

  check_cookie_approval: function() {
    var cappr = CookieManager.get_cookie("__cappr");
    if(!cappr || cappr != "Accepted") {
      $("#cookie-info").addClass('in');
    }
    else {
      $("#cookie-info").removeClass('in');
    }
  },

  cookie_approval: function() {
    var today = new Date();
    var endDate = new Date();
    endDate.setDate(today.getDate()+30);
    CookieManager.set_cookie("__cappr", "Accepted", endDate, "/");
    CookieManager.check_cookie_approval();
  }

};
