var General = {

  init: function () {
    ContactForm.init();
    Gallery.init();
    CookieManager.init();
  }

};
;
var Gallery = {

  init: function() {
    image_links = document.getElementsByClassName('image-link');
    for(var i = 0; i < image_links.length; i++) {
      image_links[i].onclick = function (event) {
        event.preventDefault();
        link = event.target.src ? event.target.parentNode : event.target;
        options = {index: link, event: event};
        blueimp.Gallery(image_links, options);
      }
    }
  }

};
;
UTIL = {
  exec: function( controller, action ) {
    var ns = SITENAME,
      action = ( action === undefined ) ? "init" : action;

    if ( controller !== "" && ns[controller] && typeof ns[controller][action] == "function" ) {
      ns[controller][action]();
    }
  },

  init: function() {
    var body = document.body,
      controller = body.getAttribute( "data-controller" ),
      action = body.getAttribute( "data-action" );

    UTIL.exec( "common" );
    UTIL.exec( controller );
    UTIL.exec( controller, action );
  }
};

SITENAME = {
  common: {
    init: function() {
      // General init
      General.init();
    }
  },

  dashboard: {
    show: function() {
      Dashboard.init();
    }
  }
};

document.addEventListener('turbolinks:load', function(e) {
  UTIL.init();
});

document.addEventListener('turbolinks:before-render', function(e) {
  // Unbinds AJAX success listener.
  $(document).unbind('ajaxSuccess');

  // Unbinds AJAX error listener.
  $(document).unbind('ajaxError');
});

